          tokens === '+-' &&
          count === -1 &&
          mergedTokens[mergedTokens.length - 1] === '['
        ) {
          mergedTokens.pop();
          lastGroup = null;
          mergedTokens.push('0');
          continue;
        } else {
          if (count) mergedTokens.push([tokens[0], count]);
          lastGroup = null;
        }
      }

      if (token === '>') lastGroup = ['><', 1];
      else if (token === '<') lastGroup = ['><', -1];
      else if (token === '+') lastGroup = ['+-', 1];
      else if (token === '-') lastGroup = ['+-', -1];
      else mergedTokens.push(token);
    }

    if (lastGroup) {
      const [tokens, count] = lastGroup;
      if (count) mergedTokens.push([tokens[0], count]);
    }

    return mergedTokens;
  }
}

