const fibonacci = n => {
  if (n === 1) return [0];
  if (n === 2) return [0, 1];
  const fib = fibonacci(n - 1);
  return fib.concat(fib[fib.length - 1] + fib[fib.length - 2]);
};

fibonacci(6); // [0, 1, 1, 2, 3, 5]

