    roll < 0.33 ? ['fresh'] : roll < 0.66 ? ['rotten'] : ['fresh', 'rotten'];

  statuses.forEach(status => {
    const originIndex = Math.floor(Math.random() * origin.length);
    collection.add({ name: fruit, status, origin: origin[originIndex] });
