  addRule(rule) {
    this.rules.push(rule);
    this.symbols.add(rule.leftHandSide);
  }

  hasSymbol(symbol) {
    return this.symbols.has(symbol);
  }

  get tokenMatchers() {
    let tokenMatchers = [];
    this.rules.forEach(rule => {
      if (rule.isTerminal) tokenMatchers.push(rule.tokenMatcher);
    });

