  const flushBuffer = () => {
    if (!buffer.length) return;

    const bufferValue = Number.parseFloat(buffer);
    if (Number.isNaN(bufferValue)) return;

    tokens.push({ type: TOKEN_TYPES.NUMBER, value: bufferValue });
    buffer = '';
