            // (int, string, double).
            IEnumerable<object> objects = new List<object> { 1, "two", 3.0, "four" };

            // Let's do the cast now
            IEnumerable<string> strings = objects.Cast<string>();

            //Cast<string>() converts each element in objects to a string.
