    {
        world.send(1, 0, std::string("Hello"));

        std::string msg;
        world.recv(1, 1, msg);

        std::cout << msg << "!" << std::endl;
    }
    else
    {
        std::string msg;
        world.recv(0, 0, msg);

        std::cout << msg << ", ";
